import { Outlet , useNavigate } from "react-router-dom";
import MainNavigation from "../components/MainNavigation";

export default function RootPage(){

    const navigate = useNavigate();

    return(
        <>
            <MainNavigation />
            <main>
                {navigate.state === 'loading' && <p></p> }
                <Outlet />
            </main>
        </>
    )
}
